fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    if n == 0 {
        return -1;
    }

    // 1. Calculate Prefix Maximums (PMax)
    let mut p_max = vec![0i64; n];
    p_max[0] = nums[0];
    for i in 1..n {
        p_max[i] = p_max[i - 1].max(nums[i]);
    }

    // 2. Calculate Suffix Minimums (SMin)
    let mut s_min = vec![0i64; n];
    s_min[n - 1] = nums[n - 1];
    for i in (0..n - 1).rev() {
        s_min[i] = s_min[i + 1].min(nums[i]);
    }

    // 3. Find the smallest stable index
    for i in 0..n {
        // Unstable value U_i = PMax[i] - SMin[i]
        let unstable_value = p_max[i] - s_min[i];

        if unstable_value <= k {
            return i as i64;
        }
    }

    // If no stable index is found
    -1
}

